// Script Continued Below
// STRY0079375
function onSubmit() {
	try{
		var reworkComments;
		var responseComments;
		var reviewer_comments;
		var comments;
		var u_reviewer_signed;
		var errorMsg;

		var formAction = g_form.getActionName();
		// All UI Actions used in the modal 
		// have the same action name as the UI Action used in the form with inModal- at the start of the name

		switch (formAction) {
			case 'inModal-rework':
				reworkComments = g_form.getValue('rework_comments');
				if(reworkComments != '') {
					return true;
				} else{
					// NOTE: this is a required field in the modal and we should never get here
					return false;
				}
			case 'inModal-inReview':
				responseComments = g_form.getValue('response');
				if(responseComments != '') {
					return true;
				} else{
					// NOTE: this is a required field in the modal and we should never get here
					return false;
				}
			case 'inModal-ClosedComplete':
// NOTE: todo - revisit this b/c closed complete could be called by a few different people
//              NEED to determine which field is required based on who is running the form
				return true;
			case 'inModal-ApproveSign-SendToReview':
			case 'inModal-ConcurSign-SendToReview':
			case 'inModal-NonconcurSign-SendToReview':
				u_reviewer_signed = g_form.getValue('u_reviewer_signed') == 'true';
				if(u_reviewer_signed){
					return true;
				}else{
					errorMsg = getMessage('Tasker - Please check the signed checkbox before submitting this task');
					g_form.addErrorMessage(errorMsg);
					return false;
				}
			case 'inModal-Concur-SendToReview':
			case 'inModal-NonConcur-SendToReview':
			case 'inModal-Reject-SendToReview':
			case 'inModal-Approve-SendToReview':
			case 'inModal-Abstain-SendToReview':
				reviewer_comments = g_form.getValue('comments_dt');
				if(reviewer_comments != '') {
					return true;
				} else{
					// NOTE: this is a required field in the modal and we should never get here
					return false;
				}
			case 'inModal-rejectOUAssignment':
			case 'inModal-rejectAssignment':
				comments = g_form.getValue('comments');
				if(comments != '') {
					return true;
				} else{
					// NOTE: this is a required field in the modal and we should never get here
					return false;
				}
			default:
				// if you got here then none of the UI Actions being handled in the modal have fired
				return;
		}
	}catch(e){
		jslog(e);
		return false;
	}
}
